{
  "mode": "method",
  "tests": [
    {
      "name": "basic_project_creation",
      "input": {
        "name": "New Project",
        "description": "A simple project description.",
        "status": "active"
      },
      "output": {
        "id": "1",
        "name": "New Project",
        "description": "A simple project description.",
        "status": "active"
      },
      "notes": "Validates basic project creation functionality."
    },
    {
      "name": "project_member_association",
      "input": {
        "projectId": "1",
        "userId": "user123",
        "role": "admin",
        "isPrimary": true
      },
      "output": {
        "projectId": "1",
        "userId": "user123",
        "role": "admin",
        "isPrimary": true
      },
      "notes": "Tests association of a user with a project."
    },
    {
      "name": "project_attachment_addition",
      "input": {
        "projectId": "1",
        "fileName": "document.pdf",
        "fileType": "application/pdf"
      },
      "output": {
        "projectId": "1",
        "attachmentId": "attach1",
        "fileName": "document.pdf",
        "fileType": "application/pdf"
      },
      "notes": "Validates the addition of an attachment to a project."
    },
    {
      "name": "duplicate_project_creation",
      "input": {
        "name": "New Project",
        "description": "A simple project description.",
        "status": "active"
      },
      "output": {
        "error": "Project with this name already exists."
      },
      "notes": "Tests handling of duplicate project names."
    },
    {
      "name": "invalid_project_status",
      "input": {
        "name": "Invalid Status Project",
        "description": "Project with invalid status.",
        "status": "unknown"
      },
      "output": {
        "error": "Invalid project status."
      },
      "notes": "Tests validation of project status."
    },
    {
      "name": "project_member_invite",
      "input": {
        "projectId": "1",
        "email": "invitee@example.com",
        "role": "viewer"
      },
      "output": {
        "projectId": "1",
        "email": "invitee@example.com",
        "role": "viewer",
        "status": "invited"
      },
      "notes": "Validates sending an invite to a project member."
    },
    {
      "name": "flattened_schema_validation",
      "input": {
        "projectId": "1"
      },
      "output": {
        "projectId": "1",
        "name": "New Project",
        "description": "A simple project description.",
        "status": "active"
      },
      "notes": "Ensures the schema is flattened and accessible."
    },
    {
      "name": "project_deletion",
      "input": {
        "projectId": "1"
      },
      "output": {
        "message": "Project deleted successfully."
      },
      "notes": "Tests the deletion of a project."
    }
  ],
  "assumptions": "All IDs are unique and auto-generated. Validations are in place for required fields.",
  "notes": "Ensure to test edge cases for validation and error handling."
}
